package kotlinx.datetime.test

import kotlinx.datetime.*
import kotlinx.datetime.format.*
import kotlin.test.*

class InstantParsingConsistencyTest {

    @Test
    fun testParseWithSecondsAndZOffset() {
        // Seconds are required, should parse successfully
        val instant = Instant.parse("2024-03-19T17:50:00Z")
        assertEquals(2024, instant.toLocalDateTime(TimeZone.UTC).year)
        assertEquals(3, instant.toLocalDateTime(TimeZone.UTC).monthNumber)
        assertEquals(19, instant.toLocalDateTime(TimeZone.UTC).dayOfMonth)
        assertEquals(17, instant.toLocalDateTime(TimeZone.UTC).hour)
        assertEquals(50, instant.toLocalDateTime(TimeZone.UTC).minute)
        assertEquals(0, instant.toLocalDateTime(TimeZone.UTC).second)
    }

    @Test
    fun testParseWithoutSecondsShouldFail() {
        // Seconds are required according to the spec, parsing should fail
        assertFailsWith<DateTimeFormatException> {
            Instant.parse("2024-03-19T17:50Z")
        }
    }

    @Test
    fun testParseWithSecondsAndNumericOffset() {
        // Parsing with seconds and numeric offset should work
        val instant = Instant.parse("2024-03-19T17:50:00+03:00")
        val utc = instant.toLocalDateTime(TimeZone.UTC)
        assertEquals(2024, utc.year)
        assertEquals(3, utc.monthNumber)
        assertEquals(19, utc.dayOfMonth)
        assertEquals(14, utc.hour) // 17:50 +03:00 = 14:50 UTC
        assertEquals(50, utc.minute)
        assertEquals(0, utc.second)
    }

    @Test
    fun testParseWithSecondsAndOffsetWithoutMinutes() {
        // Minutes of offset are optional, should parse successfully
        val instant = Instant.parse("2024-03-19T17:50:00+03")
        val utc = instant.toLocalDateTime(TimeZone.UTC)
        assertEquals(2024, utc.year)
        assertEquals(3, utc.monthNumber)
        assertEquals(19, utc.dayOfMonth)
        assertEquals(14, utc.hour) // 17:50 +03:00 = 14:50 UTC
        assertEquals(50, utc.minute)
        assertEquals(0, utc.second)
    }

    @Test
    fun testParseWithSecondsAndOffsetWithMinutes() {
        // Offset with minutes should work
        val instant = Instant.parse("2024-03-19T17:50:00+03:30")
        val utc = instant.toLocalDateTime(TimeZone.UTC)
        assertEquals(2024, utc.year)
        assertEquals(3, utc.monthNumber)
        assertEquals(19, utc.dayOfMonth)
        assertEquals(14, utc.hour) // 17:50 +03:30 = 14:20 UTC
        assertEquals(20, utc.minute)
        assertEquals(0, utc.second)
    }

    @Test
    fun testParseWithFractionalSeconds() {
        // Fractional seconds should work
        val instant = Instant.parse("2020-08-30T18:43:00.123456789Z")
        val utc = instant.toLocalDateTime(TimeZone.UTC)
        assertEquals(2020, utc.year)
        assertEquals(8, utc.monthNumber)
        assertEquals(30, utc.dayOfMonth)
        assertEquals(18, utc.hour)
        assertEquals(43, utc.minute)
        assertEquals(0, utc.second)
        assertEquals(123456789, instant.nanosecondsOfSecond)
    }

    @Test
    fun testParseWithNegativeOffset() {
        // Negative offset should work
        val instant = Instant.parse("2024-03-19T17:50:00-05:00")
        val utc = instant.toLocalDateTime(TimeZone.UTC)
        assertEquals(2024, utc.year)
        assertEquals(3, utc.monthNumber)
        assertEquals(19, utc.dayOfMonth)
        assertEquals(22, utc.hour) // 17:50 -05:00 = 22:50 UTC
        assertEquals(50, utc.minute)
        assertEquals(0, utc.second)
    }

    @Test
    fun testParseWithNegativeOffsetWithoutMinutes() {
        // Negative offset without minutes should work
        val instant = Instant.parse("2024-03-19T17:50:00-05")
        val utc = instant.toLocalDateTime(TimeZone.UTC)
        assertEquals(2024, utc.year)
        assertEquals(3, utc.monthNumber)
        assertEquals(19, utc.dayOfMonth)
        assertEquals(22, utc.hour) // 17:50 -05:00 = 22:50 UTC
        assertEquals(50, utc.minute)
        assertEquals(0, utc.second)
    }
}
"}

