package kotlinx.datetime.test

import kotlinx.datetime.*
import kotlinx.datetime.format.*
import kotlin.test.*

class InstantParsingConsistencyTest {

    @Test
    fun testParseWithSecondsAndZOffset() {
        // Seconds are required, should parse successfully
        val instant = Instant.parse("2024-03-19T17:50:00Z")
        assertEquals(2024, instant.toLocalDateTime(TimeZone.UTC).year)
        assertEquals(3, instant.toLocalDateTime(TimeZone.UTC).monthNumber)
        assertEquals(19, instant.toLocalDateTime(TimeZone.UTC).dayOfMonth)
        assertEquals(17, instant.toLocalDateTime(TimeZone.UTC).hour)
        assertEquals(50, instant.toLocalDateTime(TimeZone.UTC).minute)
        assertEquals(0, instant.toLocalDateTime(TimeZone.UTC).second)
    }

    @Test
    fun testParseWithoutSecondsShouldFail() {
        // Seconds are required according to the spec, parsing should fail
        assertFailsWith<DateTimeFormatException> {
            Instant.parse("2024-03-19T17:50Z")
        }
    }

    @Test
    fun testParseWithSecondsAndNumericOffset() {
        // Parsing with seconds and numeric offset should work
        val instant = Instant.parse("2024-03-19T17:50:00+03:00")
